/* Single class selector */
.card {
  background: white;
  border-radius: 8px;
  padding: 24px;
  border: 1px solid #e5e7eb;
}

/* Element can have multiple classes */
/* <div class="card featured"> */
.featured {
  border-color: #3b82f6;
  border-width: 2px;
}

/* Chained class: BOTH classes must be present */
.card.featured {
  box-shadow: 0 4px 12px rgba(59, 130, 246, 0.15);
}

/* Combined with element selector */
p.error {
  color: #dc2626;
  font-weight: 600;
}
span.error {
  color: #dc2626;
  font-size: 12px;
}

/* Multiple elements share a class */
/* <h2 class="section-title">...</h2>
   <h3 class="section-title">...</h3> */
.section-title {
  color: #1f2937;
  margin-bottom: 16px;
  font-weight: 700;
}

/* ID selector: very high specificity */
#main-nav {
  background: #1e293b;
  padding: 12px 24px;
  display: flex;
}

/* Problem: ID is hard to override */
#main-nav { color: white; }          /* 0,1,0,0 */
.nav-light { color: #333; }          /* 0,0,1,0 - loses! */
.nav-light.themed { color: #333; }   /* 0,0,2,0 - still loses! */

/* You'd need another ID or !important to override */
#main-nav.nav-light { color: #333; } /* 0,1,1,0 - finally wins */

/* BETTER: Use classes instead */
.main-nav {
  background: #1e293b;
  padding: 12px 24px;
  display: flex;
  color: white;
}
.main-nav.light {
  background: white;
  color: #333;  /* Easy to override with classes */
}

/* Block: standalone component */
.search-form {
  display: flex;
  gap: 8px;
  padding: 16px;
  background: #f9fafb;
  border-radius: 8px;
}

/* Element: part of the block (double underscore) */
.search-form__input {
  flex: 1;
  padding: 8px 12px;
  border: 1px solid #d1d5db;
  border-radius: 4px;
  font-size: 14px;
}

.search-form__button {
  padding: 8px 20px;
  background: #2563eb;
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}

/* Modifier: variation of block or element (double hyphen) */
.search-form--large {
  padding: 24px;
}

.search-form__button--disabled {
  background: #9ca3af;
  cursor: not-allowed;
}

.search-form__button--secondary {
  background: #6b7280;
}

