/* Hover: mouse is over the element */
.btn {
  background-color: #2563eb;
  color: white;
  padding: 10px 20px;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  transition: background-color 0.2s;
}

.btn:hover {
  background-color: #1d4ed8;
}

.btn:active {
  background-color: #1e40af;
  transform: scale(0.98);
}

/* Focus-visible: keyboard navigation only */
.btn:focus-visible {
  outline: 3px solid #93c5fd;
  outline-offset: 2px;
}

/* Link pseudo-classes (LVHA order) */
a:link { color: #2563eb; }
a:visited { color: #7c3aed; }
a:hover { color: #1d4ed8; text-decoration: underline; }
a:active { color: #1e40af; }

/* First and last child */
li:first-child {
  font-weight: bold;
}

li:last-child {
  border-bottom: none;
}

/* nth-child: powerful positional targeting */
tr:nth-child(odd) {
  background-color: #f9fafb;  /* Zebra-striped table rows */
}

tr:nth-child(even) {
  background-color: white;
}

/* Every 3rd element */
.grid-item:nth-child(3n) {
  margin-right: 0;
}

/* First 3 elements */
li:nth-child(-n+3) {
  color: #059669;
  font-weight: 600;
}

/* Only child: element with no siblings */
.tab:only-child {
  border-radius: 8px;
}

/* nth-of-type: counts only matching elements */
p:nth-of-type(1) {
  font-size: 1.25rem; /* First <p>, ignoring other elements */
}

/* :not() - select everything EXCEPT */
nav a:not(.active) {
  opacity: 0.7;
}

nav a:not(.active):hover {
  opacity: 1;
}

/* All children except the last */
.list li:not(:last-child) {
  border-bottom: 1px solid #e5e7eb;
}

/* Form pseudo-classes */
input:focus {
  border-color: #3b82f6;
  outline: none;
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.1);
}

input:disabled {
  background-color: #f3f4f6;
  cursor: not-allowed;
  opacity: 0.6;
}

input:valid {
  border-color: #10b981;
}

input:invalid {
  border-color: #ef4444;
}

input:placeholder-shown {
  border-color: #d1d5db; /* Show neutral border when empty */
}

