/* Required field indicator */
label.required::after {
  content: " *";
  color: #ef4444;
  font-weight: bold;
}

/* Quotation marks */
.quote::before {
  content: "\201C"; /* Left double quotation mark */
  font-size: 3rem;
  color: #d1d5db;
  line-height: 0;
  vertical-align: -0.4em;
  margin-right: 4px;
}

/* Decorative line after heading */
.section-title::after {
  content: "";
  display: block;
  width: 60px;
  height: 3px;
  background-color: #3b82f6;
  margin-top: 8px;
  border-radius: 2px;
}

/* External link indicator */
a[href^="https"]::after {
  content: " \2197"; /* North-east arrow */
  font-size: 0.8em;
}

/* Tooltip arrow using ::after */
.tooltip {
  position: relative;
  background: #1e293b;
  color: white;
  padding: 8px 16px;
  border-radius: 6px;
  display: inline-block;
}

.tooltip::after {
  content: "";
  position: absolute;
  bottom: -6px;
  left: 50%;
  transform: translateX(-50%);
  width: 0;
  height: 0;
  border-left: 6px solid transparent;
  border-right: 6px solid transparent;
  border-top: 6px solid #1e293b;
}

/* Card with colored top border using ::before */
.feature-card {
  position: relative;
  background: white;
  padding: 24px;
  border-radius: 8px;
  overflow: hidden;
}

.feature-card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4px;
  background-color: #3b82f6;
}

/* Drop cap: large first letter */
.article-body::first-letter {
  font-size: 3.5rem;
  font-weight: bold;
  float: left;
  line-height: 1;
  margin-right: 8px;
  margin-top: 4px;
  color: #1e40af;
}

/* First line styling */
.article-body::first-line {
  font-weight: 600;
  color: #111827;
}

/* Custom placeholder styling */
input::placeholder {
  color: #9ca3af;
  font-style: italic;
  font-size: 14px;
}

/* Custom text selection */
::selection {
  background-color: #3b82f6;
  color: white;
}

/* Selection on specific elements */
.brand-text::selection {
  background-color: #f59e0b;
  color: #1e293b;
}

